prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?choreo ?start ?end (COUNT(DISTINCT ?reachable) AS ?reachableCount)
WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "2d225c9ff86b443c9f6bc6cfe687afbc" ;
         tai:belongsTo ?org .

  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .

  ?start a bboExt:StartEvent ;
         tai:belongsTo ?choreo .
  OPTIONAL { ?start bbo:name ?startName . }

  ?end a bboExt:EndEvent ;
       tai:belongsTo ?choreo .

  {
    ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?reachable .
    ?reachable a bboExt:EndEvent .
  }
  FILTER(STRENDS(STR(?end), STR(?end)))
}
GROUP BY ?choreo ?start ?end
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?origId ?normId
WHERE {
  ?model a bboExt:Model ;
         tai:belongsTo ?org ;
         bbo:name ?modelName .
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  FILTER(
    STRENDS(STR(?origId), "2d225c9ff86b443c9f6bc6cfe687afbc") ||
    STRENDS(STR(?normId), "2d225c9ff86b443c9f6bc6cfe687afbc") ||
    CONTAINS(LCASE(STR(?modelName)), LCASE("2d225c9ff86b443c9f6bc6cfe687afbc"))
  )
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?start ?startName (COUNT(DISTINCT ?end) AS ?endReachableCount)
       (GROUP_CONCAT(DISTINCT ?endName; separator=" | ") AS ?reachableEndNames)
WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId ?anyNorm ;
         tai:originalId "2d225c9ff86b443c9f6bc6cfe687afbc" ;
         tai:belongsTo ?org .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .

  ?start a bboExt:StartEvent ;
         tai:belongsTo ?choreo .
  OPTIONAL { ?start bbo:name ?startName . }

  OPTIONAL {
    ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?end .
    ?end a bboExt:EndEvent ;
         tai:belongsTo ?choreo .
    OPTIONAL { ?end bbo:name ?endName . }
  }
}
GROUP BY ?start ?startName
ORDER BY DESC(?endReachableCount)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
ASK {
  ?model a bboExt:Model ;
         tai:originalId "2d225c9ff86b443c9f6bc6cfe687afbc" ;
         tai:belongsTo ?org .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .

  ?start a bboExt:StartEvent ;
         tai:belongsTo ?choreo .

  FILTER NOT EXISTS {
    ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?end .
    ?end a bboExt:EndEvent ;
         tai:belongsTo ?choreo .
  }
}
